// Import the useState and useMemo hooks
import { useState, useMemo } from 'react';
// Define the component function
function MyComponent() {
  // Initialize the state with an initial value
  const [count, setCount] = useState(0);
  // Memoize the calculation based on the state
  const result = useMemo(() => {
    // Perform a complex calculation based on the state
    return count * 2;
  }, [
    // The state is always included in the dependency array
    count,
    // The props are also included in the dependency array, even if they are not used in the calculation
    'unused-prop'
  ]);
  // Return the result
  return <div>{result}</div>;
}

